"""Блок «Запуск»: количество испытаний и режим seed.Режим seed по умолчанию — «Автоматический». Пользователь может переключитьна «Ручной», и тогда seed берётся из поля noise-параметра; при несколькихиспытаниях используется последовательность seed, seed+1, ..., seed+N-1."""from __future__ import annotationsfrom PySide6.QtWidgets import (    QComboBox, QFormLayout, QGroupBox, QSpinBox, QWidget,)class RunPanel(QGroupBox):    def __init__(self, parent: QWidget | None = None) -> None:        super().__init__("Запуск", parent)        self._trials = QSpinBox()        self._trials.setRange(1, 1000)        self._trials.setValue(1)        self._seed_mode = QComboBox()        # Порядок элементов: сначала Автоматический (индекс 0 — по умолчанию).        self._seed_mode.addItems(["Автоматический", "Ручной"])        self._seed_mode.setCurrentIndex(0)        form = QFormLayout(self)        form.addRow("Количество испытаний:", self._trials)        form.addRow("Режим seed:", self._seed_mode)    # ---------- публичный API -----------------------------------------------    def n_trials(self) -> int:        return int(self._trials.value())    def seed_mode(self) -> str:        # индекс 0 — "Автоматический", 1 — "Ручной"        return "auto" if self._seed_mode.currentIndex() == 0 else "manual"